const t=JSON.parse('{"key":"v-7da5f727","path":"/posts/%E6%89%93%E5%B7%A5%E4%BA%BA%E6%89%8B%E5%86%8C/%E8%81%8C%E5%9C%BA%E7%9A%84%E5%A4%A9%E8%8A%B1%E6%9D%BF.html","title":"","lang":"en-US","frontmatter":{"description":"之前写了篇文章，里面提到了三个点，是横亘在职场上的三张大网。里面只提到了第一个大网，牢牢的把大家框定在年薪100w左右。每多赚一分，都要付出极其高昂的税收。 这三个大网比你想象中的要来得早，分别是：税收，带不走的位置，ROE的下滑。我们挨个讲解，今天讲第二个大网：带不走的位置。 一、职场的套现 假设你是小王，你在公司负责A、B、C三个业务，还带领着几个新人，几个老人，一起推进这些业务。你自己都感觉自己很重要，领导也自然是这样这样觉得。事情给你办，领导很放心。你一天十多个电话小会议，把各个业务线串了起来。你有一张大的表格，里面记录着每个人当前做什么。你每天下午都会再系统性的review一遍这个内容。很多时候，深夜你也被拉起来看问题，很多时候，一些事情你不在场都没法进行去决策。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/posts/%E6%89%93%E5%B7%A5%E4%BA%BA%E6%89%8B%E5%86%8C/%E8%81%8C%E5%9C%BA%E7%9A%84%E5%A4%A9%E8%8A%B1%E6%9D%BF.html"}],["meta",{"property":"og:site_name","content":"入川为王"}],["meta",{"property":"og:description","content":"之前写了篇文章，里面提到了三个点，是横亘在职场上的三张大网。里面只提到了第一个大网，牢牢的把大家框定在年薪100w左右。每多赚一分，都要付出极其高昂的税收。 这三个大网比你想象中的要来得早，分别是：税收，带不走的位置，ROE的下滑。我们挨个讲解，今天讲第二个大网：带不走的位置。 一、职场的套现 假设你是小王，你在公司负责A、B、C三个业务，还带领着几个新人，几个老人，一起推进这些业务。你自己都感觉自己很重要，领导也自然是这样这样觉得。事情给你办，领导很放心。你一天十多个电话小会议，把各个业务线串了起来。你有一张大的表格，里面记录着每个人当前做什么。你每天下午都会再系统性的review一遍这个内容。很多时候，深夜你也被拉起来看问题，很多时候，一些事情你不在场都没法进行去决策。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"en-US"}],["meta",{"property":"og:updated_time","content":"2025-08-16T04:25:11.000Z"}],["meta",{"property":"article:author","content":"入川为王"}],["meta",{"property":"article:modified_time","content":"2025-08-16T04:25:11.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2025-08-16T04:25:11.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"入川为王\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[],"git":{"createdTime":1755318311000,"updatedTime":1755318311000,"contributors":[{"name":"TikTrack Developer","email":"user@example.com","commits":1}]},"readingTime":{"minutes":7.66,"words":2297},"filePathRelative":"posts/打工人手册/职场的天花板.md","localizedDate":"August 16, 2025","excerpt":"<p>之前写了篇文章，里面提到了三个点，是横亘在职场上的三张大网。里面只提到了第一个大网，牢牢的把大家框定在年薪100w左右。每多赚一分，都要付出极其高昂的税收。</p>\\n<p>这三个大网比你想象中的要来得早，分别是：税收，带不走的位置，ROE的下滑。我们挨个讲解，今天讲第二个大网：<strong>带不走的位置</strong>。</p>\\n<h4> <strong>一、职场的套现</strong></h4>\\n<p>假设你是小王，你在公司负责A、B、C三个业务，还带领着几个新人，几个老人，一起推进这些业务。你自己都感觉自己很重要，领导也自然是这样这样觉得。<strong>事情给你办，领导很放心</strong>。你一天十多个电话小会议，把各个业务线串了起来。你有一张大的表格，里面记录着每个人当前做什么。你每天下午都会再系统性的review一遍这个内容。很多时候，深夜你也被拉起来看问题，很多时候，一些事情你不在场都没法进行去决策。</p>","autoDesc":true}');export{t as data};
